//sprites made
var dog = createSprite(349, 462);
dog.setAnimation("cyl");
dog.scale = 0.52;
var topRocks = createSprite(0, 20);
topRocks.setAnimation("plants_28_1");
topRocks.scale = 0.2;
var groundRocks = createSprite(-15, 365);
groundRocks.setAnimation("rocks_1");
groundRocks.scale = 0.3;

var treat = createSprite(-2, 200);
treat.setAnimation("chickenleg_1");
treat.scale = 0.1;

//velocity sets
treat.velocityX = 3;
topRocks.velocityX = randomNumber(3, 8);
groundRocks.velocityX = randomNumber(3, 8);

//variables
var score = 0;
var health = 100;
var started = false;

//introduction slide
function showIntro() {
  background("lightblue");

  fill("black");
  textSize(27);
  text("Dog WALK Adventure GAME", 25, 120);

  textSize(18);
  text("Press SPACE to jump", 100, 170);
  text("Avoid rocks to keep HEALTH", 50, 200);
  text("Collect TEN treats to win!", 70, 230);

  textSize(16);
  text("Press ENTER to start", 105, 280);
}

// ground drawn
function drawGround() {
  fill("green");       
  rect(0, 300, 500, 300);  
}

//controls collsions and what happens
function checkCollisions() {
 if (dog.isTouching(treat)) {
    score = score + 1;
    treat.x = 0;
    treat.y = randomNumber(100, 240);
  }

 if (dog.isTouching(topRocks)) {
    health = health - 10;
    topRocks.x = -90;
  }

 if (dog.isTouching(groundRocks)) {
    health = health - 10;
    groundRocks.x = -92;
  }
}

//stats: health/score
function displayStats() {
  fill("black");
  textSize(20);
  text("Score:", 10, 30);
  text(score, 75, 30);

  text("Health:", 280, 30);
  text(health, 350, 30);
}

function draw() {

  // SHOW INTRO FIRST
  if (started === false) {

    showIntro();

    //human input 1: into exiting
    if (keyDown("enter")) {
      started = true;
    }

  } else {

    //background
    background("lightblue");

    displayStats();
    drawGround();
    checkCollisions();


    //spikes looping
    if (topRocks.x > 330) {
      topRocks.x = -80;
      topRocks.velocityX = randomNumber(3 + score/10, 8 + score/10); 
    }
    if (groundRocks.x > 360) {
      groundRocks.x = -152;
      groundRocks.velocityX = randomNumber(3 + score/10, 8 + score/10); 
    }

    //treat respawning
    if (390 < treat.x) {
      treat.x = 10;
      treat.y = randomNumber(0, 260);
    }

    //human input 2: jumping ability
    if (keyDown("space")) {
      if (dog.y >= 295) {
        dog.velocityY = -14.5;
      }
    }

    dog.velocityY = dog.velocityY + 0.5;

    if (dog.y > 320) {
      dog.y = 320;
      dog.velocityY = 0;
    }


    drawSprites();

    //scoring
    fill("black");
    textSize(20);
    text("Score:", 10, 30);
    text(score, 75, 30);

    text("Health:", 280, 30);
    text(health, 350, 30);

    //game over
    if (health <= 0) {
      background("red");
      fill("white");
      textSize(30);
      text("GAME OVER", 110, 200);
    }

    //win
    if (score > 9) {
      background("pink");
      fill("white");
      textSize(40);
      text("You Win! Congrats!", 20, 200);
    }
  }
}
